> [!tip] 理解提示（非原文）
> Bole 前端没有选择 TypeScript，而是用 `.js` + JSDoc 注释提供类型提示。这是务实的选择 -- 在团队规模不大、迭代速度优先的项目中，JSDoc 提供了足够的类型安全感，同时避免了 `.ts` 带来的编译步骤和类型体操开销。

### 3. API 层设计

API 层是前端架构中最关键的基础设施层。Bole 的设计遵循一个硬性约束：**组件中禁止出现任何 `fetch()` 或 `axios.()` 直接调用。**

#### 3.1 base.js 的核心封装

```javascript
// web/src/apis/base.js -- 核心封装模式

import request from '@/utils/request'

// 通用 GET 请求
export async function apiGet(url, params = {}, config = {}) {
  const response = await request.get(url, { params, ...config })
  return response.data
}

// 通用 POST 请求
export async function apiPost(url, data = {}, config = {}) {
  const response = await request.post(url, data, config)
  return response.data
}

// 管理端 GET 请求（自动注入管理端 prefix）
export async function apiAdminGet(url, params = {}) {
  return apiGet(`/admin${url}`, params)
}

// 管理端 POST 请求
export async function apiAdminPost(url, data = {}) {
  return apiPost(`/admin${url}`, data)
}

// 带文件上传的请求（自动设置 Content-Type）
export async function apiUpload(url, formData, onProgress) {
  const response = await request.post(url, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
    onUploadProgress: onProgress
  })
  return response.data
}
```

#### 3.2 统一拦截器设计

```javascript
// web/src/utils/request.js -- axios 实例与拦截器

import axios from 'axios'
import { useUserStore } from '@/stores/user'
import router from '@/router'
import { message } from 'ant-design-vue'

const request = axios.create({
  baseURL: import.meta.env.VITE_API_BASE_URL || '/api',
  timeout: 30000,
})

// 请求拦截器：自动注入 Token
request.interceptors.request.use(
  (config) => {
    const userStore = useUserStore()
    if (userStore.token) {
      config.headers.Authorization = `Bearer ${userStore.token}`
    }
    return config
  },
  (error) => Promise.reject(error)
)

// 响应拦截器：统一错误处理
request.interceptors.response.use(
  (response) => response,
  (error) => {
    const { status, data } = error.response || {}
    switch (status) {
      case 401:
        // Token 过期 → 清除状态 → 跳转登录页
        useUserStore().logout()
        router.push({ name: 'Login', query: { redirect: router.currentRoute.value.fullPath } })
        break
      case 403:
        message.error('权限不足，无法执行此操作')
        break
      case 500:
        message.error(data?.detail || '服务器内部错误，请稍后重试')
        break
      default:
        message.error(data?.detail || '请求失败')
    }
    return Promise.reject(error)
  }
)

export default request
```

> [!note] 译者注（非原文）
> 拦截器中调用 `useUserStore()` 不会违反 Pinia 的"在 setup 外使用"规则，因为拦截器在请求发起时（运行时）才执行，此时 Pinia 实例已经完成注册。

#### 3.3 按模块拆分的 API 文件

```javascript
// web/src/apis/chat.js -- 聊天模块 API

import { apiGet, apiPost } from './base'

// 发送消息（SSE 流）
export function sendChatMessage(agentId, conversationId, message, files) {
  // SSE 流不经过 axios，使用原生 EventSource
  // 此处返回配置对象供 composable 使用
  return {
    url: `/api/agents/${agentId}/chat`,
    body: { conversation_id: conversationId, message, files }
  }
}

// 获取对话历史
export function getConversationHistory(conversationId) {
  return apiGet(`/api/conversations/${conversationId}/messages`)
}

// 获取对话列表
export function listConversations(params) {
  return apiGet('/api/conversations', params)
}

// 删除对话
export function deleteConversation(conversationId) {
  return request.delete(`/api/conversations/${conversationId}`)
}
```

```javascript
// web/src/apis/knowledge.js -- 知识库模块 API

import { apiGet, apiPost, apiUpload } from './base'

export function listDatabases() {
  return apiGet('/api/knowledge/databases')
}

export function createDatabase(name, config) {
  return apiPost('/api/knowledge/databases', { name, ...config })
}

export function uploadDocument(databaseId, file, onProgress) {
  const formData = new FormData()
  formData.append('file', file)
  return apiUpload(`/api/knowledge/databases/${databaseId}/documents`, formData, onProgress)
}

export function getDocumentStatus(databaseId, documentId) {
  return apiGet(`/api/knowledge/databases/${databaseId}/documents/${documentId}/status`)
}
```

#### 3.4 为什么禁止在组件中散落 HTTP 请求

| 问题 | 散落 HTTP 请求的后果 | API 层统一管理的收益 |
|------|---------------------|---------------------|
| Token 注入 | 每个组件手动拼接 headers | 拦截器自动注入，零遗漏 |
| 错误处理 | 每个组件重复 try-catch + message.error | 拦截器统一处理，组件只需关注成功分支 |
| 类型安全 | 请求/响应的数据形状不可知 | API 函数签名即类型约定 |
| 可测试性 | 组件测试需要 mock 网络层 | 只需 mock API 函数 |
| 重构成本 | URL 变动需要全局搜索替换 | 只改一个文件 |
| Token 刷新 | 组件层面几乎无法正确处理 401 | 拦截器中统一静默刷新 Token |

这条规则的反例：如果面试对话组件在 6 处不同的代码位置直接调用 `axios.post('/api/chat')`，那么当后端将路由从 `/api/chat` 迁移到 `/api/v2/conversations` 时，你需要修改 6 处、排查 6 处、测试 6 处。API 层将这一负担压缩为一行修改。

### 4. Pinia 状态管理

Bole 使用 **Composition API setup 函数语法** 定义所有 Pinia store。这是 Vue 3 生态的最新推荐写法，与 Options API 写法对比如下：

```javascript
// 风格 A：Options API（Vue 2 / 早期 Pinia）
export const useCounterStore = defineStore('counter', {
  state: () => ({ count: 0 }),
  getters: {
    double: (state) => state.count * 2,
  },
  actions: {
    increment() { this.count++ },
  },
})

// 风格 B：Composition API setup（Bole 采用）
export const useCounterStore = defineStore('counter', () => {
  const count = ref(0)
  const double = computed(() => count.value * 2)
  function increment() { count.value++ }
  return { count, double, increment }
})
```

**为什么 Bole 选 B 而不选 A**：
1. 与 Vue 组件中的 `<script setup>` 风格完全统一，心智模型一致
2. 可以在 store 内部使用 `watch`、`watchEffect` 等 Composition API
3. TypeScript / JSDoc 类型推导更自然（没有 `this` 的类型问题）
4. 支持组合（compose）多个 store 时直接用 `ref` / `reactive` 解构

#### 4.1 五大核心 Store

```javascript
// web/src/stores/user.js -- 认证状态（精简示意）

export const useUserStore = defineStore('user', () => {
  const token = ref(localStorage.getItem('token') || '')
  const userInfo = ref(null)
  const isAuthenticated = computed(() => !!token.value)
  const isAdmin = computed(() => userInfo.value?.role === 'admin')
  const isSuperAdmin = computed(() => userInfo.value?.role === 'super_admin')

  async function login(username, password) {
    const res = await authAPI.login(username, password)
    token.value = res.access_token
    localStorage.setItem('token', res.access_token)
    await fetchUserInfo()
  }

  async function fetchUserInfo() {
    userInfo.value = await authAPI.getUserInfo()
  }

  function logout() {
    token.value = ''
    userInfo.value = null
    localStorage.removeItem('token')
  }

  return { token, userInfo, isAuthenticated, isAdmin, isSuperAdmin,
           login, fetchUserInfo, logout }
})
```

```javascript
// web/src/stores/chatUI.js -- 聊天界面状态

export const useChatUIStore = defineStore('chatUI', () => {
  const messages = ref([])          // 当前对话的消息列表
  const isLoading = ref(false)      // 是否正在等待 AI 回复
  const streamingContent = ref('')  // 当前流式输出的累积内容
  const error = ref(null)           // 错误状态

  function addMessage(message) {
    messages.value.push(message)
  }

  function appendToLastMessage(chunk) {
    const last = messages.value[messages.value.length - 1]
    if (last && last.role === 'assistant') {
      last.content += chunk
    }
  }

  function clearMessages() {
    messages.value = []
    streamingContent.value = ''
    error.value = null
  }

  return { messages, isLoading, streamingContent, error,
           addMessage, appendToLastMessage, clearMessages }
})

// web/src/stores/theme.js -- 暗色模式

export const useThemeStore = defineStore('theme', () => {
  const isDark = ref(localStorage.getItem('theme') === 'dark')
  // Ant Design Vue ConfigProvider 需要的主题 token 覆写
  const themeConfig = computed(() => ({
    token: {
      colorPrimary: isDark.value ? '#4f8cff' : '#1677ff',
      borderRadius: 6,
    },
    algorithm: isDark.value ? theme.darkAlgorithm : theme.defaultAlgorithm,
  }))

  function toggleTheme() {
    isDark.value = !isDark.value
    localStorage.setItem('theme', isDark.value ? 'dark' : 'light')
    // 同步更新 <html> 的 data-theme 属性，供 CSS 变量使用
    document.documentElement.setAttribute('data-theme',
      isDark.value ? 'dark' : 'light')
  }

  return { isDark, themeConfig, toggleTheme }
})
```

> [!warning] 易混点（非原文）
> Pinia store 中的 `ref` 在暴露后会自动解包（unwrap），组件中使用时不需要 `.value`。但 store 内部函数里操作 state 仍然需要 `.value`。这是 Pinia 对 Composition API 的适配处理，不同于组件 `<script setup>` 中 `ref` 在模板里自动解包。

### 5. Vue Router 路由设计

#### 5.1 布局分层

Bole 有两套布局，通过路由的 `meta.layout` 字段区分：

```javascript
// web/src/router/index.js -- 路由配置核心结构

const routes = [
  // ========== AppLayout（侧边栏+顶栏，需要认证） ==========
  {
    path: '/',
    component: () => import('@/layouts/AppLayout.vue'),
