#### 5.2 路由守卫

```javascript
// 全局前置守卫
router.beforeEach(async (to, from, next) => {
  const userStore = useUserStore()

  // 1. 认证检查
  const requiresAuth = to.matched.some(r => r.meta.requiresAuth !== false)
  // 所有 AppLayout 子路由默认 requireAuth
  if (requiresAuth && !userStore.isAuthenticated) {
    return next({ name: 'Login', query: { redirect: to.fullPath } })
  }

  // 2. 管理员权限检查
  const requiresAdmin = to.meta.requiresAdmin
  if (requiresAdmin && !userStore.isAdmin) {
    return next({ name: 'Agent' })  // 非管理员 → 重定向到对话页
  }

  // 3. 超级管理员权限检查
  const requiresSuperAdmin = to.meta.requiresSuperAdmin
  if (requiresSuperAdmin && !userStore.isSuperAdmin) {
    return next({ name: 'Dashboard' })
  }

  // 4. 已登录用户访问 /auth/* → 重定向到主页
  if (to.path.startsWith('/auth') && userStore.isAuthenticated) {
    return next({ name: 'Agent' })
  }

  next()
})
```

**非管理员重定向策略**：普通用户访问 `/admin/*` 路由时，Bole 不会展示 403 页面，而是静默重定向到 `/agent`（智能体对话页）。这种设计的理由有二：(1) 避免让普通用户感知到"受限区域"的存在，减少困惑；(2) 对话页是用户最可能想去的地方，重定向到此处最不生硬。

### 6. 组件设计体系

#### 6.1 AgentChat -- 核心聊天组件

AgentChat 是前端最复杂的组件，它需要同时处理：用户消息展示、AI 流式回复渲染、工具调用结果可视化、消息撤销/重发、对话历史加载。

```javascript
// web/src/components/AgentChat/AgentChat.vue -- 核心结构

<script setup>
import { ref, computed, watch, nextTick } from 'vue'
import { useChatUIStore } from '@/stores/chatUI'
import { useUserStore } from '@/stores/user'
import ToolCallingResult from '@/components/ToolCallingResult/ToolCallingResult.vue'
import SourcesPanel from '@/components/sources/SourcesPanel.vue'
import { useSSE } from '@/composables/useSSE'

const props = defineProps({
  agentId: { type: String, required: true },
  conversationId: { type: String, default: null },
  placeholder: { type: String, default: '输入你的问题...' }
})

const emit = defineEmits(['conversation-created', 'title-changed'])

const chatUI = useChatUIStore()
const inputText = ref('')
const messageContainer = ref(null)

// 发送消息 -- 启动 SSE 流
async function handleSend() {
  if (!inputText.value.trim() || chatUI.isLoading) return

  // 1. 添加用户消息到列表
  const userMsg = { id: Date.now(), role: 'user', content: inputText.value }
  chatUI.addMessage(userMsg)
  inputText.value = ''

  // 2. 创建 AI 占位消息
  const assistantMsg = { id: Date.now() + 1, role: 'assistant', content: '' }
  chatUI.addMessage(assistantMsg)
  chatUI.isLoading = true

  // 3. 启动 SSE 流
  const { start, stop } = useSSE({
    url: `/api/agents/${props.agentId}/chat`,
    body: { conversation_id: props.conversationId, message: userMsg.content },
    onMessage: (chunk) => {
      chatUI.appendToLastMessage(chunk)
      scrollToBottom()
    },
    onToolCall: (toolCall) => {
      // 工具调用事件 → 插入 ToolCallingResult 卡片
      chatUI.addToolCall(toolCall)
    },
    onDone: () => {
      chatUI.isLoading = false
    },
    onError: (err) => {
      chatUI.error = err
      chatUI.isLoading = false
    }
  })
  start()
}
</script>
```

#### 6.2 ToolCallingResult -- 工具调用结果可视化

当 Agent 在对话中调用工具（如检索知识库、执行代码、查询数据库），后端通过 SSE 推送 `tool_call` 事件。前端将其渲染为内嵌卡片：

```javascript
// web/src/components/ToolCallingResult/ToolCallingResult.vue -- 结构示意

const props = defineProps({
  toolName: String,      // 'knowledge_search', 'code_execution', 'web_search'
  toolInput: Object,     // 工具的输入参数
  toolOutput: Object,    // 工具的输出结果
  status: String         // 'running' | 'success' | 'error'
})

// 根据 toolName 映射不同的展示组件
const componentMap = {
  knowledge_search: 'KnowledgeSearchResult',
  code_execution: 'CodeExecutionResult',
  web_search: 'WebSearchResult',
}
```

工具调用的 UI 设计要点：
- `running` 状态：显示骨架屏（Skeleton），告知用户"正在检索知识库..."
- `success` 状态：折叠卡片展示，默认只显示摘要，点击展开详情
- `error` 状态：显示红色的错误摘要，不阻塞对话流

#### 6.3 组件通信方式总结

| 通信场景 | 使用方式 | 原则 |
|----------|----------|------|
| 父子组件数据传递 | `props`（父→子）+ `emits`（子→父） | 单向数据流 |
| 跨组件共享状态 | Pinia store | 避免多层 props drilling |
| 兄弟组件通信 | Pinia store 或父组件中转 | 不直接通信 |
| 工具调用结果注入 | store + 动态组件 | 解耦展示逻辑 |
| Portal / 全局通知 | `message.info()` / `notification.open()` | Ant Design 提供 |

